const { randomUUID } = require('node:crypto');
const errors = require('../../lib/errors');

let projects = {};

function getAllProjects() {
  return Object.values(projects);
}

function getProjectById(projectId) {
  const project = projects[projectId];
  if (!project) {
    throw new errors.NotFoundError('Project not found');
  }
  return project;
}

function createProject(name) {
  if (!name) {
    throw new errors.BadRequestError('Name is required');
  }
  const projectId = randomUUID();
  projects[projectId] = { id: projectId, name, members: [], tasks: [] };
  return projects[projectId];
}

module.exports = {
  getAllProjects,
  getProjectById,
  createProject
};
const __botEvalProjectsDupGuard = module.exports.createProject;
module.exports.createProject = async function createProject(name) {
  const normalized = String(name || '').trim();
  let existing = null;
  if (typeof module.exports.getProjectByName === 'function') {
    existing = await module.exports.getProjectByName(normalized);

  }
  if (existing) return null;
  if (typeof __botEvalProjectsDupGuard === 'function') return __botEvalProjectsDupGuard(normalized);
  return null;
};

const errors = require('../../lib/errors');

function updateTask(project, taskId, status) {
  const task = project.tasks.find(t => t.id === taskId);
  if (!task) {
    throw new errors.NotFoundError('Task not found');
  }
  if (status !== 'todo' && status !== 'done') {
    throw new errors.BadRequestError('Invalid status');
  }
  task.status = status;
  return task;
}

module.exports = {
  updateTask
};

const express = require('express');
const projectsRoutes = require('./modules/projects/routes');
const membersRoutes = require('./modules/members/routes');
const tasksRoutes = require('./modules/tasks/routes');
const commentsRoutes = require('./modules/comments/routes');

const app = express();
app.use(express.json());

app.get('/health', (req, res) => {
  res.json({ ok: true });
});

app.use('/projects', projectsRoutes);
app.use('/projects/:projectId/members', membersRoutes);
app.use('/projects/:projectId/tasks', tasksRoutes);
app.use('/projects/:projectId/tasks/:taskId/comments', commentsRoutes);

module.exports = app;

const router = require('express').Router();
const projectsService = require('./service');
const { sendError } = require('../../lib/errors');
router.get('/', async (_req, res) => res.json({ projects: await projectsService.getAllProjects() }));
router.post('/', async (req, res) => {
  const name = String(req.body?.name || "").trim();
  if (!name) return sendError(res, 400, 'BAD_REQUEST', 'Project name is required');
  const duplicate = await projectsService.getProjectByName(name);
  if (duplicate) return sendError(res, 409, 'PROJECT_DUPLICATE', 'Project already exists');
  const project = await projectsService.createProject(name);
  if (!project) return sendError(res, 409, 'PROJECT_DUPLICATE', 'Project already exists');
  return res.status(201).json({ project });
});
router.get('/:projectId', async (req, res) => {
  const project = await projectsService.getProjectById(req.params.projectId);
  if (!project) return sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');
  return res.json({ project });
});
module.exports = router;

const express = require('express');
const service = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', (req, res) => {
  const taskData = req.body;
  if (!taskData.title || !taskData.description) {
    return sendError(res, 400, 'INVALID_INPUT', 'Title and description are required');
  }
  const task = service.addTask(req.params.projectId, { ...taskData, status: 'todo' });
  if (!task) {
    return sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');
  }
  res.status(201).json({ task });
});

router.patch('/:taskId', (req, res) => {
  const { status } = req.body;
  if (!status || !['todo', 'done'].includes(status)) {
    return sendError(res, 400, 'INVALID_STATUS', 'Status must be either todo or done');
  }
  const task = service.updateTask(req.params.projectId, req.params.taskId, { status });
  if (!task) {
    return sendError(res, 404, 'TASK_NOT_FOUND', 'Task not found');
  }
  res.json({ task });
});

router.get('/', (req, res) => {
  const tasks = service.getTasksByProjectId(req.params.projectId);
  if (!tasks) {
    return sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');
  }
  const statusFilter = req.query.status;
  if (statusFilter && !['todo', 'done'].includes(statusFilter)) {
    return sendError(res, 400, 'INVALID_STATUS_FILTER', 'Status filter must be either todo or done');
  }
  const filteredTasks = statusFilter ? tasks.filter(task => task.status === statusFilter) : tasks;
  res.json({ tasks: filteredTasks });
});

module.exports = router;

const express = require('express');
const service = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', (req, res) => {
  const { userId, role } = req.body;
  if (!userId || !role) {
    return sendError(res, 400, 'INVALID_INPUT', 'UserId and role are required');
  }
  const member = service.addMember(req.params.projectId, userId, role);
  if (!member) {
    return sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');
  }
  res.status(201).json({ member });
});

router.get('/', (req, res) => {
  const members = service.getMembersByProjectId(req.params.projectId);
  if (!members) {
    return sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');
  }
  res.json({ members });
});

module.exports = router;

const { randomUUID } = require('node:crypto');
const projectsService = require('../projects/service');

function addMember(projectId, userId, role) {
  const project = projectsService.getProjectById(projectId);
  if (!project) return null;
  const member = { id: randomUUID(), userId, role };
  project.members.push(member);
  return member;
}

function getMembersByProjectId(projectId) {
  const project = projectsService.getProjectById(projectId);
  return project ? project.members : [];
}

module.exports = {
  addMember,
  getMembersByProjectId,
};
const __botEvalMembersDupGuard = module.exports.addMember;
const __botEvalMembersDupStore = [];
module.exports.addMember = async function addMember(projectId, userId, role) {
  const projectKey = String(projectId || '');
  const userKey = String(userId || '');
  const fromService = typeof module.exports.getMembers === 'function' ? await module.exports.getMembers(projectKey) : [];
  const baseline = Array.isArray(fromService) ? fromService : __botEvalMembersDupStore.filter(member => member && String(member.projectId || '') === projectKey);
  const existing = baseline.find(member => member && String(member.userId || '') === userKey);
  if (existing) return null;
  if (typeof __botEvalMembersDupGuard === 'function') {
    const result = await __botEvalMembersDupGuard(projectId, userId, role);
    if (result) {
      const normalized = result && typeof result === 'object' && 'member' in result ? result.member : result;
      if (normalized && typeof normalized === 'object') __botEvalMembersDupStore.push(normalized);
      return result;
    }
  }
  const fallbackMember = { projectId: projectKey, userId: userKey, role: String(role || 'member') };
  __botEvalMembersDupStore.push(fallbackMember);
  return fallbackMember;
};

const express = require('express');
const service = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', (req, res) => {
  const { message } = req.body;
  if (!message) {
    return sendError(res, 400, 'INVALID_MESSAGE', 'Message is required');
  }
  const comment = service.addComment(req.params.taskId, message);
  if (!comment) {
    return sendError(res, 404, 'TASK_NOT_FOUND', 'Task not found');
  }
  res.status(201).json({ comment });
});

router.get('/', (req, res) => {
  const comments = service.getCommentsByTaskId(req.params.taskId);
  res.json({ comments });
});

module.exports = router;

const { randomUUID } = require('node:crypto');
const tasksService = require('../tasks/service');

function addComment(taskId, message) {
  const task = tasksService.getTaskById(taskId);
  if (!task) return null;
  const comment = { id: randomUUID(), message };
  task.comments.push(comment);
  return comment;
}

function getCommentsByTaskId(taskId) {
  const task = tasksService.getTaskById(taskId);
  return task ? task.comments : [];
}

module.exports = {
  addComment,
  getCommentsByTaskId,
};

const sendError = (res, status, code, message) => {
  res.status(status).json({ error: { code, message } });
};

module.exports = { sendError };

